#include <stdio.h>
#include <stdlib.h>
#include <math.h>

typedef struct { float x, y, z; } V;
typedef struct { V o, d; } Ray;
typedef struct { float t; V p, n; int hit; } Hit;

static V norm(V v){
    float l = sqrtf(v.x*v.x + v.y*v.y + v.z*v.z);
    V r = { v.x/l, v.y/l, v.z/l };
    return r;
}

static const float SCx = 0.0f, SCy = -0.5f, SCz = -5.0f, SR = 1.0f;

static Hit sphere_hit(Ray ray){
    Hit h; h.hit = 0; h.t = 0.0f;
    h.p.x = h.p.y = h.p.z = 0.0f; h.n = h.p;
    float ocx = ray.o.x - SCx, ocy = ray.o.y - SCy, ocz = ray.o.z - SCz;
    float a = ray.d.x*ray.d.x + ray.d.y*ray.d.y + ray.d.z*ray.d.z;
    float hb = ocx*ray.d.x + ocy*ray.d.y + ocz*ray.d.z;
    float b = hb + hb;
    float c = ocx*ocx + ocy*ocy + ocz*ocz - SR*SR;
    float disc = b*b - 4.0f*a*c;
    if (disc < 0.0f) return h;
    double sq = sqrt((double)disc);
    double nb = (double)(-b);
    double a2 = (double)(a + a);
    float t = (float)((nb - sq)/a2);
    if (t < 0.001f) {
        t = (float)((nb + sq)/a2);
        if (t < 0.001f) return h;
    }
    h.t = t;
    h.p.x = ray.o.x + ray.d.x*t;
    h.p.y = ray.o.y + ray.d.y*t;
    h.p.z = ray.o.z + ray.d.z*t;
    V nn = { h.p.x - SCx, h.p.y - SCy, h.p.z - SCz };
    h.n = norm(nn);
    h.hit = 1;
    return h;
}

static V trace(Ray ray, V light){
    Hit s = sphere_hit(ray);
    int obj = 0;
    V P, N;
    P.x = P.y = P.z = 0.0f; N = P;
    if (1e-4f > fabsf(ray.d.y)) {
        if (s.hit){ obj=1; P=s.p; N=s.n; }
    } else {
        float tp = -1.5f / ray.d.y;
        if (0.001f > tp) {
            if (s.hit){ obj=1; P=s.p; N=s.n; }
        } else {
            if (s.hit && !(tp > s.t)) {
                obj=2;
            } else if (s.hit) {
                obj=1; P=s.p; N=s.n;
            } else {
                obj=2;
            }
            if (obj==2){
                P.x = ray.o.x + ray.d.x*tp;
                P.y = ray.o.y + ray.d.y*tp;
                P.z = ray.o.z + ray.d.z*tp;
                N.x = 0.0f; N.y = 1.0f; N.z = 0.0f;
            }
        }
    }
    if (obj==0){
        float t = (ray.d.y + 1.0f)*0.5f;
        float om = 1.0f - t;
        V c = { t*0.5f + om, t*0.7f + om, t + om };
        return c;
    }
    V so = { P.x + 0.001f*N.x, P.y + 0.001f*N.y, P.z + 0.001f*N.z };
    Ray sr = { so, norm(light) };
    Hit sh = sphere_hit(sr);
    float intensity;
    if (sh.hit) intensity = 0.2f;
    else {
        float dot = N.x*light.x + N.y*light.y + N.z*light.z;
        float dif = (float)fmax((double)dot, 0.0);
        intensity = dif*0.8f + 0.2f;
    }
    V col;
    if (obj==1){
        col.x = intensity;
        col.y = intensity*0.2f;
        col.z = intensity*0.2f;
    } else {
        int par = (int)((double)floorf(P.x) + (double)floorf(P.z));
        float cc = (par & 1) ? 0.4f : 0.9f;
        col.x = cc*intensity; col.y = cc*intensity; col.z = cc*intensity;
    }
    return col;
}

int main(void){
    int W = 800, H = 600;
    fprintf(stderr, "Creating high-resolution image: %dx%d\n", W, H);
    fputs("This will be downsampled with ffmpeg after rendering\n", stderr);
    V light = norm((V){1.0f, 1.0f, -1.0f});
    float **img = malloc(sizeof(float*)*H);
    for (int y=0;y<H;y++) img[y] = malloc(sizeof(float)*W*3);
    fputs("Rendering high-resolution image...\n", stderr);
    for (int y=0;y<H;y++){
        fprintf(stderr, "\rProgress: %.1f%%", 100.0f*y/600.0f);
        float ry = 1.0f - y/599.0f;
        float ry2 = ry + ry;
        float diry = ry2 - 1.0f;
        for (int x=0;x<W;x++){
            float u = x/799.0f;
            float dirx = u*2.6666667f - 1.3333334f;
            Ray ray;
            ray.o.x = 0.0f; ray.o.y = 0.0f; ray.o.z = 0.0f;
            ray.d = norm((V){dirx, diry, -1.0f});
            V col = trace(ray, light);
            img[y][x*3+0] = col.x;
            img[y][x*3+1] = col.y;
            img[y][x*3+2] = col.z;
        }
    }
    fputs("\nRendering complete\n", stderr);
    FILE *fp = fopen("image.ppm", "w");
    if (!fp){ fprintf(stderr, "Error: Could not open file %s for writing\n", "image.ppm"); return 1; }
    fprintf(fp, "P3\n%d %d\n255\n", W, H);
    for (int y=0;y<H;y++){
        for (int x=0;x<W;x++){
            int b[3];
            for (int k=0;k<3;k++){
                double d = fmin(fmax((double)img[y][x*3+k], 0.0), 1.0);
                b[k] = (int)((float)d * 255.99f);
            }
            fprintf(fp, "%d %d %d\n", b[0], b[1], b[2]);
        }
    }
    fclose(fp);
    fprintf(stderr, "Wrote image to %s\n", "image.ppm");
    for (int y=0;y<H;y++) free(img[y]);
    free(img);
    fputs("Done.\n", stderr);
    return 0;
}
